-- CreateTable
CREATE TABLE "CandidateRecommendationLog" (
    "id" TEXT NOT NULL,
    "sourceAgentRunId" TEXT NOT NULL,
    "batchTag" TEXT NOT NULL,
    "symbol" TEXT NOT NULL,
    "sector" TEXT NOT NULL,
    "accountType" TEXT NOT NULL,
    "score" INTEGER NOT NULL,
    "vsSpx" DOUBLE PRECISION NOT NULL,
    "momentum1Y" DOUBLE PRECISION,
    "recommendationType" TEXT NOT NULL,
    "recommendedAt" TIMESTAMP(3) NOT NULL,
    "outcome30d" DOUBLE PRECISION,
    "outcome90d" DOUBLE PRECISION,
    "notes" TEXT,
    "createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,

    CONSTRAINT "CandidateRecommendationLog_pkey" PRIMARY KEY ("id")
);

-- CreateIndex
CREATE INDEX "CandidateRecommendationLog_batchTag_idx" ON "CandidateRecommendationLog"("batchTag");

-- CreateIndex
CREATE INDEX "CandidateRecommendationLog_symbol_recommendedAt_idx" ON "CandidateRecommendationLog"("symbol", "recommendedAt");

-- AddForeignKey
ALTER TABLE "CandidateRecommendationLog" ADD CONSTRAINT "CandidateRecommendationLog_sourceAgentRunId_fkey" FOREIGN KEY ("sourceAgentRunId") REFERENCES "AgentRun"("id") ON DELETE RESTRICT ON UPDATE CASCADE;

